    if index_path.exists() {
        fs::remove_file(index_path).map_err(ApiError::internal)?;
    }
    git_index_command(
        Command::new("git")
            .arg("--git-dir")
            .arg(repo_path)
            .arg("read-tree")
            .arg("--empty"),
