        &plan.helper_config_key,
        &plan.helper_config_value,
    ])?;
    run_git(&[
        "config",
        "--global",
        "--replace-all",
        &plan.use_http_path_config_key,
        "true",
    ])?;
    approve_git_credential(&plan.credential_fields)?;
    let clone_args = plan
        .clone_args
        .iter()
        .map(String::as_str)
