            },
            message: if partial {
                "Projected public update".to_string()
            } else {
                logical.message.clone()
            },
            changes: visible_changes,
        });

        last_visible = Some(projected_id);
        process_projection_boundary_events_after(
            &mut commits,
            &mut last_visible,
            &boundary_events,
            Some(logical.id.as_str()),
            view_key,
